// TestCountEmbeddingsInKV_OnlyCountsGenerated verifies that only records with
// status "generated" are counted, not "pending" or "failed".
func TestCountEmbeddingsInKV_OnlyCountsGenerated(t *testing.T) {
	mgr, mockBuckets := setupTestManager(t)
	ctx := context.Background()

	embeddingBucket := mockBuckets["EMBEDDING_INDEX"]

	// Create records with different statuses
	records := []struct {
		entityID string
		status   embedding.Status
	}{
		{"entity-1", embedding.StatusGenerated},
		{"entity-2", embedding.StatusGenerated},
		{"entity-3", embedding.StatusPending},
		{"entity-4", embedding.StatusFailed},
		{"entity-5", embedding.StatusGenerated},
	}

	for _, rec := range records {
		record := &embedding.Record{
			EntityID:    rec.entityID,
			Status:      rec.status,
			ContentHash: "hash-" + rec.entityID,
		}
		if rec.status == embedding.StatusGenerated {
			record.Vector = []float32{0.1, 0.2, 0.3}
			record.GeneratedAt = time.Now()
		}

		data, err := json.Marshal(record)
		require.NoError(t, err)
		embeddingBucket.data[rec.entityID] = data
	}

	count, err := mgr.CountEmbeddingsInKV(ctx)

	require.NoError(t, err)
	require.Equal(t, 3, count, "Should only count records with status=generated (3), not pending or failed")
}

